// // This comment suggests that the register will not update its value on the rising edge of the clock when the load signal is asserted.
module register(
    input wire clk,
    input wire load,
    input wire [7:0] d,
    output reg [7:0] q
);

always @(posedge clk) begin
    if (load) begin
        q <= d;
    end
end

endmodule
